import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  linkedSignal,
  model,
  output,
  viewChild,
} from '@angular/core';
import { ControlValueAccessor } from '@angular/forms';

import { injectFormControl } from '../../utils/form-control';
import { mergeClasses } from '../../utils/merge-classes';
import { CalendarGridComponent } from './calendar-grid.component';
import { CalendarNavigationComponent } from './calendar-navigation.component';
import type { CalendarMode, CalendarValue, DisabledDateFn } from './calendar.types';
import {
  generateCalendarDays,
  getSelectedDatesArray,
  getWeekdayLabels,
  isSameDay,
  makeSafeDate,
  normalizeCalendarValue,
} from './calendar.utils';
import { calendarVariants } from './calendar.variants';

@Component({
  selector: 'n-calendar, [n-calendar]',
  standalone: true,
  imports: [CalendarNavigationComponent, CalendarGridComponent],
  template: `
    <div [class]="classes()" data-slot="root">
      <n-calendar-navigation
        [currentMonth]="currentMonthValue()"
        [currentYear]="currentYearValue()"
        [minDate]="nMin()"
        [maxDate]="nMax()"
        [disabled]="isDisabled()"
        [locale]="nLocale()"
        (monthChange)="onMonthChange($event)"
        (yearChange)="onYearChange($event)"
        (previousMonth)="previousMonth()"
        (nextMonth)="nextMonth()"
      />

      <n-calendar-grid
        [calendarDays]="calendarDays()"
        [weekdayLabels]="weekdayLabels()"
        [disabled]="isDisabled()"
        (dateSelect)="onDateSelect($event)"
        (previousMonth)="onGridPreviousMonth($event)"
        (nextMonth)="onGridNextMonth($event)"
        (navigateYear)="onNavigateYear($event)"
      />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[attr.tabindex]': '0' },
  exportAs: 'nCalendar',
})
export class CalendarComponent implements ControlValueAccessor {
  private readonly gridRef = viewChild.required(CalendarGridComponent);
  private readonly _form = injectFormControl<CalendarValue>(this);

  readonly nMode    = input<CalendarMode>('single');
  readonly nValue   = model<CalendarValue>(null);
  readonly nMin     = input<Date | null>(null);
  readonly nMax     = input<Date | null>(null);
  readonly nDisabled    = input<boolean>(false);
  readonly nDisabledDate = input<DisabledDateFn | null>(null);
  readonly nLocale  = input<string>(typeof navigator !== 'undefined' ? navigator.language : 'en-US');
  readonly nWeekStartsOn = input<0 | 1>(0);
  readonly nClass   = input<string>('');
  readonly nId      = input<string>('');

  readonly nChange = output<CalendarValue>();

  protected readonly isDisabled = computed(() => this.nDisabled() || this._form.disabledByForm());

  private readonly normalizedValue = computed(() => normalizeCalendarValue(this.nValue()));

  private readonly currentDate = computed(() => {
    const val = this.normalizedValue();
    if (!val) return new Date();
    if (val instanceof Date) return val;
    if (Array.isArray(val) && val.length > 0) return val[0];
    return new Date();
  });

  protected readonly currentMonthValue = linkedSignal(() => this.currentDate().getMonth().toString());
  protected readonly currentYearValue  = linkedSignal(() => this.currentDate().getFullYear().toString());

  protected readonly classes = computed(() => mergeClasses(calendarVariants(), this.nClass()));

  protected readonly weekdayLabels = computed(() =>
    getWeekdayLabels(this.nLocale(), this.nWeekStartsOn()),
  );

  protected readonly calendarDays = computed(() => {
    const currentDate = this.currentDate();
    const navDate = makeSafeDate(
      Number.parseInt(this.currentYearValue()),
      Number.parseInt(this.currentMonthValue()),
      currentDate.getDate(),
    );
    const resolved = Number.isNaN(navDate.getTime()) ? currentDate : navDate;

    return generateCalendarDays({
      year: resolved.getFullYear(),
      month: resolved.getMonth(),
      mode: this.nMode(),
      selectedDates: getSelectedDatesArray(this.normalizedValue(), this.nMode()),
      minDate: this.nMin(),
      maxDate: this.nMax(),
      disabled: this.isDisabled(),
      disabledDateFn: this.nDisabledDate(),
    });
  });

  protected onMonthChange(monthIndex: string): void {
    const parsed = Number.parseInt(monthIndex, 10);
    if (Number.isNaN(parsed) || parsed < 0 || parsed > 11) return;

    const year = Number.parseInt(this.currentYearValue());
    const safe = makeSafeDate(Number.isNaN(year) ? this.currentDate().getFullYear() : year, parsed, 1);
    this.currentMonthValue.set(safe.getMonth().toString());
    this.gridRef().setFocusedDayIndex(-1);
  }

  protected onYearChange(year: string): void {
    const parsed = Number.parseInt(year, 10);
    if (Number.isNaN(parsed) || parsed < 1900 || parsed > 2100) return;

    const month = Number.parseInt(this.currentMonthValue());
    const safe = makeSafeDate(parsed, Number.isNaN(month) ? this.currentDate().getMonth() : month, 1);
    this.currentYearValue.set(safe.getFullYear().toString());
    this.gridRef().setFocusedDayIndex(-1);
  }

  protected previousMonth(): void {
    const month = Number.parseInt(this.currentMonthValue());
    const year  = Number.parseInt(this.currentYearValue());
    const date  = makeSafeDate(year, month - 1, 1);
    this.currentMonthValue.set(date.getMonth().toString());
    this.currentYearValue.set(date.getFullYear().toString());
    this.gridRef().setFocusedDayIndex(-1);
  }

  protected nextMonth(): void {
    const month = Number.parseInt(this.currentMonthValue());
    const year  = Number.parseInt(this.currentYearValue());
    const date  = makeSafeDate(year, month + 1, 1);
    this.currentMonthValue.set(date.getMonth().toString());
    this.currentYearValue.set(date.getFullYear().toString());
    this.gridRef().setFocusedDayIndex(-1);
  }

  protected onNavigateYear(direction: number): void {
    const year  = Number.parseInt(this.currentYearValue());
    const month = Number.parseInt(this.currentMonthValue());
    const base  = Number.isNaN(year) ? this.currentDate().getFullYear() : year;
    const baseM = Number.isNaN(month) ? this.currentDate().getMonth() : month;
    const date  = makeSafeDate(base + direction, baseM, 1);
    this.currentYearValue.set(date.getFullYear().toString());
    setTimeout(() => this.gridRef().resetFocus(), 0);
  }

  protected onGridPreviousMonth(event: { position: string; dayOfWeek: number }): void {
    this.previousMonth();
    setTimeout(() => this.resetFocusAfterNavigation(event.position, event.dayOfWeek), 0);
  }

  protected onGridNextMonth(event: { position: string; dayOfWeek: number }): void {
    this.nextMonth();
    setTimeout(() => this.resetFocusAfterNavigation(event.position, event.dayOfWeek), 0);
  }

  protected onDateSelect(event: { date: Date; index: number }): void {
    this.selectDate(event.date);
  }

  /** Resets calendar navigation to display the currently selected date's month/year. */
  resetNavigation(): void {
    const val = this.currentDate();
    this.currentMonthValue.set(val.getMonth().toString());
    this.currentYearValue.set(val.getFullYear().toString());
    this.gridRef().setFocusedDayIndex(-1);
  }

  private selectDate(date: Date): void {
    if (this.isDisabled()) return;

    const mode    = this.nMode();
    const current = this.normalizedValue();

    let next: CalendarValue;

    if (mode === 'single') {
      next = date;
    } else if (mode === 'multiple') {
      const dates = Array.isArray(current) ? [...current] : [];
      const idx   = dates.findIndex(d => isSameDay(d, date));
      if (idx >= 0) dates.splice(idx, 1);
      else dates.push(date);
      next = dates.length > 0 ? dates : null;
    } else {
      const dates = Array.isArray(current) ? [...current] : [];
      if (dates.length === 0) {
        next = [date];
      } else if (dates.length === 1) {
        const start = dates[0];
        if (isSameDay(date, start)) next = null;
        else if (date.getTime() < start.getTime()) next = [date, start];
        else next = [start, date];
      } else {
        next = [date];
      }
    }

    this.nValue.set(next);
    this._form.notifyChange(next);
    this.nChange.emit(next);
    this._form.notifyTouched();
  }

  private resetFocusAfterNavigation(position = 'default', dayOfWeek = -1): void {
    const days = this.calendarDays();
    let targetIndex = -1;

    switch (position) {
      case 'first':
        targetIndex = days.findIndex(d => !d.isDisabled);
        break;
      case 'last':
        for (let i = days.length - 1; i >= 0; i--) {
          if (!days[i].isDisabled) { targetIndex = i; break; }
        }
        break;
      case 'firstWeek':
        if (dayOfWeek >= 0) targetIndex = this.findEnabledFrom(dayOfWeek, days);
        break;
      case 'lastWeek':
        if (dayOfWeek >= 0) {
          const lastWeekStart = Math.floor((days.length - 1) / 7) * 7;
          targetIndex = this.findEnabledFrom(Math.min(lastWeekStart + dayOfWeek, days.length - 1), days);
        }
        break;
      default: {
        const sel   = days.findIndex(d => d.isSelected);
        const today = days.findIndex(d => d.isToday && d.isCurrentMonth);
        const first = days.findIndex(d => d.isCurrentMonth && !d.isDisabled);
        targetIndex = sel >= 0 ? sel : today >= 0 ? today : Math.max(first, 0);
        break;
      }
    }

    if (targetIndex >= 0) this.gridRef().setFocusedDayIndex(targetIndex);
  }

  private findEnabledFrom(start: number, days: { isDisabled: boolean }[]): number {
    const s = Math.max(0, Math.min(start, days.length - 1));
    for (let i = s; i < days.length; i++) { if (!days[i].isDisabled) return i; }
    for (let i = s - 1; i >= 0; i--) { if (!days[i].isDisabled) return i; }
    return s;
  }

  writeValue(value: CalendarValue): void {
    this.nValue.set(value);
  }

  registerOnChange(fn: (value: CalendarValue) => void): void {
    this._form.setOnChange(fn);
  }

  registerOnTouched(fn: () => void): void {
    this._form.setOnTouched(fn);
  }

  setDisabledState(isDisabled: boolean): void {
    this._form.setDisabledByForm(isDisabled);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  computed,
  input,
  output,
  signal,
  viewChild,
} from '@angular/core';

import { mergeClasses } from '../../utils/merge-classes';
import type { CalendarDay } from './calendar.types';
import { getDayAriaLabel, getDayId } from './calendar.utils';
import { calendarDayButtonVariants, calendarDayVariants, calendarWeekdayVariants } from './calendar.variants';

@Component({
  selector: 'n-calendar-grid',
  standalone: true,
  template: `
    <div #gridContainer>
      <div class="grid w-fit grid-cols-7 text-center" role="row">
        @for (label of weekdayLabels(); track label) {
          <div [class]="weekdayClasses()" role="columnheader" aria-label="{{ label }}">
            {{ label }}
          </div>
        }
      </div>

      <div class="mt-1 grid w-fit auto-rows-min grid-cols-7" role="rowgroup">
        @for (day of calendarDays(); track day.date.getTime(); let i = $index) {
          <div [class]="dayContainerClasses()" role="gridcell">
            <button
              type="button"
              [id]="getDayId(i)"
              [class]="dayButtonClasses(day)"
              (click)="onDayClick(day.date, i)"
              [disabled]="day.isDisabled"
              [attr.aria-selected]="day.isSelected"
              [attr.aria-label]="getDayAriaLabel(day)"
              [attr.tabindex]="getFocusedDayIndex() === i ? 0 : -1"
              role="button"
            >
              {{ day.date.getDate() }}
            </button>
          </div>
        }
      </div>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: 'flex justify-center',
    '[attr.role]': '"grid"',
    '(keydown.ArrowLeft.prevent)': 'onKeyDown($event)',
    '(keydown.ArrowRight.prevent)': 'onKeyDown($event)',
    '(keydown.ArrowUp.prevent)': 'onKeyDown($event)',
    '(keydown.ArrowDown.prevent)': 'onKeyDown($event)',
    '(keydown.Home.prevent)': 'onKeyDown($event)',
    '(keydown.End.prevent)': 'onKeyDown($event)',
    '(keydown.PageUp.prevent)': 'onKeyDown($event)',
    '(keydown.PageDown.prevent)': 'onKeyDown($event)',
    '(keydown.Enter.prevent)': 'onKeyDown($event)',
    '(keydown.Space.prevent)': 'onKeyDown($event)',
  },
  exportAs: 'nCalendarGrid',
})
export class CalendarGridComponent {
  private readonly gridContainer = viewChild.required<ElementRef<HTMLElement>>('gridContainer');

  readonly calendarDays = input.required<CalendarDay[]>();
  readonly weekdayLabels = input.required<string[]>();
  readonly disabled = input<boolean>(false);

  readonly dateSelect = output<{ date: Date; index: number }>();
  readonly previousMonth = output<{ position: string; dayOfWeek: number }>();
  readonly nextMonth = output<{ position: string; dayOfWeek: number }>();
  readonly navigateYear = output<number>();

  private readonly focusedDayIndex = signal<number>(-1);

  protected readonly weekdayClasses = computed(() => mergeClasses(calendarWeekdayVariants()));
  protected readonly dayContainerClasses = computed(() => mergeClasses(calendarDayVariants()));

  protected dayButtonClasses(day: CalendarDay): string {
    return mergeClasses(
      calendarDayButtonVariants({
        selected: day.isSelected,
        today: day.isToday,
        outside: !day.isCurrentMonth,
        disabled: day.isDisabled,
        rangeStart: day.isRangeStart ?? false,
        rangeEnd: day.isRangeEnd ?? false,
        inRange: day.isInRange ?? false,
      }),
    );
  }

  protected onDayClick(date: Date, index: number): void {
    if (this.disabled()) return;
    this.focusedDayIndex.set(index);
    this.dateSelect.emit({ date, index });
  }

  protected getDayId(index: number): string {
    return getDayId(index);
  }

  protected getDayAriaLabel(day: CalendarDay): string {
    return getDayAriaLabel(day);
  }

  protected getFocusedDayIndex(): number {
    const focused = this.focusedDayIndex();
    if (focused >= 0) return focused;

    const days = this.calendarDays();
    const selectedIndex = days.findIndex(d => d.isSelected);
    if (selectedIndex >= 0) return selectedIndex;

    const todayIndex = days.findIndex(d => d.isToday && d.isCurrentMonth);
    if (todayIndex >= 0) return todayIndex;

    const firstEnabled = days.findIndex(d => d.isCurrentMonth && !d.isDisabled);
    return firstEnabled >= 0 ? firstEnabled : 0;
  }

  setFocusedDayIndex(index: number): void {
    this.focusedDayIndex.set(index);
    this.setFocus(index);
  }

  resetFocus(): void {
    this.setFocus(this.getFocusedDayIndex());
  }

  onKeyDown(e: Event): void {
    if (this.disabled()) return;

    const event = e as KeyboardEvent;
    const days = this.calendarDays();
    if (days.length === 0) return;

    const currentIndex = this.getFocusedDayIndex();
    let newIndex: number | null = null;

    switch (event.key) {
      case 'ArrowLeft':  newIndex = this.navigate(currentIndex, -1, days); break;
      case 'ArrowRight': newIndex = this.navigate(currentIndex, 1, days);  break;
      case 'ArrowUp':    newIndex = this.navigate(currentIndex, -7, days); break;
      case 'ArrowDown':  newIndex = this.navigate(currentIndex, 7, days);  break;
      case 'Home':
        newIndex = this.findEnabledInRange(Math.floor(currentIndex / 7) * 7, Math.floor(currentIndex / 7) * 7 + 6, days);
        break;
      case 'End':
        newIndex = this.findEnabledInRange(Math.floor(currentIndex / 7) * 7 + 6, Math.floor(currentIndex / 7) * 7, days, true);
        break;
      case 'PageUp':
        if (event.ctrlKey) this.navigateYear.emit(-1);
        else this.previousMonth.emit({ position: 'default', dayOfWeek: -1 });
        break;
      case 'PageDown':
        if (event.ctrlKey) this.navigateYear.emit(1);
        else this.nextMonth.emit({ position: 'default', dayOfWeek: -1 });
        break;
      case 'Enter':
      case ' ': {
        const focusedDay = days[currentIndex];
        if (focusedDay && !focusedDay.isDisabled) {
          this.dateSelect.emit({ date: focusedDay.date, index: currentIndex });
        }
        break;
      }
      default: break;
    }

    if (newIndex !== null && newIndex !== currentIndex) {
      this.setFocus(newIndex);
    }
  }

  private navigate(currentIndex: number, step: number, days: CalendarDay[]): number | null {
    const targetIndex = currentIndex + step;

    if (targetIndex >= 0 && targetIndex < days.length) {
      return this.findEnabledInRange(targetIndex, currentIndex, days);
    }

    const dayOfWeek = currentIndex % 7;
    if (step === -1) this.previousMonth.emit({ position: 'last', dayOfWeek: -1 });
    else if (step === 1) this.nextMonth.emit({ position: 'first', dayOfWeek: -1 });
    else if (step === -7) this.previousMonth.emit({ position: 'lastWeek', dayOfWeek });
    else if (step === 7) this.nextMonth.emit({ position: 'firstWeek', dayOfWeek });

    return null;
  }

  private findEnabledInRange(start: number, fallback: number, days: CalendarDay[], reverse = false): number {
    const clampedStart = Math.max(0, Math.min(start, days.length - 1));
    const clampedFallback = Math.max(0, Math.min(fallback, days.length - 1));

    if (!reverse) {
      for (let i = clampedStart; i < days.length; i++) {
        if (!days[i].isDisabled) return i;
      }
      for (let i = clampedStart - 1; i >= 0; i--) {
        if (!days[i].isDisabled) return i;
      }
    } else {
      for (let i = clampedStart; i >= 0; i--) {
        if (!days[i].isDisabled) return i;
      }
      for (let i = clampedStart + 1; i < days.length; i++) {
        if (!days[i].isDisabled) return i;
      }
    }

    return clampedFallback;
  }

  private setFocus(index: number): void {
    this.focusedDayIndex.set(index);
    setTimeout(() => {
      const el = this.gridContainer()?.nativeElement.querySelector(`#${getDayId(index)}`) as HTMLElement;
      el?.focus();
    }, 0);
  }
}

import { ChangeDetectionStrategy, Component, computed, input, output } from '@angular/core';

import { ButtonComponent } from '../button/button.component';
import { getMonthNames } from './calendar.utils';
import { calendarNavVariants } from './calendar.variants';
import { mergeClasses } from '../../utils/merge-classes';

@Component({
  selector: 'n-calendar-navigation',
  standalone: true,
  imports: [ButtonComponent],
  template: `
    <div [class]="navClasses()">
      <button
        type="button"
        n-button
        nVariant="ghost"
        nSize="sm"
        (click)="onPreviousClick()"
        [disabled]="isPreviousDisabled()"
        aria-label="Previous month"
        class="size-7 p-0"
      >
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" class="size-4" aria-hidden="true">
          <path d="m15 18-6-6 6-6" stroke-linecap="round" stroke-linejoin="round" />
        </svg>
      </button>

      <div class="flex items-center gap-1">
        <select
          [value]="currentMonth()"
          (change)="onMonthChange($event)"
          [disabled]="disabled()"
          class="h-7 cursor-pointer appearance-none rounded-sm bg-transparent px-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
          aria-label="Select month"
        >
          @for (name of monthNames(); track $index) {
            <option [value]="$index.toString()">{{ name }}</option>
          }
        </select>

        <select
          [value]="currentYear()"
          (change)="onYearChange($event)"
          [disabled]="disabled()"
          class="h-7 cursor-pointer appearance-none rounded-sm bg-transparent px-1 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
          aria-label="Select year"
        >
          @for (year of availableYears(); track year) {
            <option [value]="year.toString()">{{ year }}</option>
          }
        </select>
      </div>

      <button
        type="button"
        n-button
        nVariant="ghost"
        nSize="sm"
        (click)="onNextClick()"
        [disabled]="isNextDisabled()"
        aria-label="Next month"
        class="size-7 p-0"
      >
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" class="size-4" aria-hidden="true">
          <path d="m9 18 6-6-6-6" stroke-linecap="round" stroke-linejoin="round" />
        </svg>
      </button>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  exportAs: 'nCalendarNavigation',
})
export class CalendarNavigationComponent {
  readonly currentMonth = input.required<string>();
  readonly currentYear = input.required<string>();
  readonly minDate = input<Date | null>(null);
  readonly maxDate = input<Date | null>(null);
  readonly disabled = input<boolean>(false);
  readonly locale = input<string>('en-US');

  readonly monthChange = output<string>();
  readonly yearChange = output<string>();
  readonly previousMonth = output<void>();
  readonly nextMonth = output<void>();

  protected readonly navClasses = computed(() => mergeClasses(calendarNavVariants()));

  protected readonly monthNames = computed(() => getMonthNames(this.locale()));

  protected readonly availableYears = computed(() => {
    const minYear = this.minDate()?.getFullYear() ?? new Date().getFullYear() - 100;
    const maxYear = this.maxDate()?.getFullYear() ?? new Date().getFullYear() + 50;
    const years: number[] = [];
    for (let i = minYear; i <= maxYear; i++) years.push(i);
    return years;
  });

  protected readonly isPreviousDisabled = computed(() => {
    if (this.disabled()) return true;
    const minDate = this.minDate();
    if (!minDate) return false;
    const month = Number.parseInt(this.currentMonth());
    const year = Number.parseInt(this.currentYear());
    const lastDayOfPrevMonth = new Date(year, month, 0);
    return lastDayOfPrevMonth.getTime() < minDate.getTime();
  });

  protected readonly isNextDisabled = computed(() => {
    if (this.disabled()) return true;
    const maxDate = this.maxDate();
    if (!maxDate) return false;
    const month = Number.parseInt(this.currentMonth());
    const year = Number.parseInt(this.currentYear());
    const nextMonthStart = new Date(year, month + 1, 1);
    return nextMonthStart.getTime() > maxDate.getTime();
  });

  protected onPreviousClick(): void {
    this.previousMonth.emit();
  }

  protected onNextClick(): void {
    this.nextMonth.emit();
  }

  protected onMonthChange(event: Event): void {
    const value = (event.target as HTMLSelectElement).value;
    this.monthChange.emit(value);
  }

  protected onYearChange(event: Event): void {
    const value = (event.target as HTMLSelectElement).value;
    this.yearChange.emit(value);
  }
}

export type CalendarMode = 'single' | 'multiple' | 'range';
export type CalendarValue = Date | Date[] | null;
export type DisabledDateFn = (date: Date) => boolean;

export interface CalendarDay {
  date: Date;
  isCurrentMonth: boolean;
  isToday: boolean;
  isSelected: boolean;
  isDisabled: boolean;
  isRangeStart?: boolean;
  isRangeEnd?: boolean;
  isInRange?: boolean;
}

export interface CalendarDayConfig {
  year: number;
  month: number;
  mode: CalendarMode;
  selectedDates: Date[];
  minDate: Date | null;
  maxDate: Date | null;
  disabled: boolean;
  disabledDateFn: DisabledDateFn | null;
}

import type { CalendarDay, CalendarDayConfig, CalendarMode, CalendarValue } from './calendar.types';

export function isSameDay(date1: Date, date2: Date): boolean {
  return (
    date1.getFullYear() === date2.getFullYear() &&
    date1.getMonth() === date2.getMonth() &&
    date1.getDate() === date2.getDate()
  );
}

export function isDateDisabled(date: Date, minDate: Date | null, maxDate: Date | null): boolean {
  if (minDate && date < minDate) return true;
  if (maxDate && date > maxDate) return true;
  return false;
}

export function makeSafeDate(year: number, month: number, day = 1): Date {
  const date = new Date(year, month, day);
  date.setHours(12, 0, 0, 0);
  return date;
}

export function generateCalendarDays(config: CalendarDayConfig): CalendarDay[] {
  const { year, month, mode, selectedDates, minDate, maxDate, disabled, disabledDateFn } = config;

  const today = new Date();
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);

  const startDate = new Date(firstDay);
  startDate.setDate(startDate.getDate() - startDate.getDay());

  const endDate = new Date(lastDay);
  endDate.setDate(endDate.getDate() + (6 - endDate.getDay()));

  const days: CalendarDay[] = [];
  const cur = new Date(startDate);

  let rangeStart: Date | null = null;
  let rangeEnd: Date | null = null;
  if (mode === 'range' && selectedDates.length > 0) {
    rangeStart = selectedDates[0];
    rangeEnd = selectedDates.length > 1 ? selectedDates[1] : null;
  }

  while (cur <= endDate) {
    const date = new Date(cur);
    const isCurrentMonth = date.getMonth() === month;
    const isToday = isSameDay(date, today);
    const isDisabledDate =
      disabled ||
      isDateDisabled(date, minDate, maxDate) ||
      (disabledDateFn ? disabledDateFn(date) : false);

    let isSelected = false;
    let isRangeStart = false;
    let isRangeEnd = false;
    let isInRange = false;

    if (mode === 'single') {
      isSelected = selectedDates.length > 0 && isSameDay(date, selectedDates[0]);
    } else if (mode === 'multiple') {
      isSelected = selectedDates.some(d => isSameDay(date, d));
    } else if (mode === 'range') {
      if (rangeStart && isSameDay(date, rangeStart)) {
        isRangeStart = true;
        isSelected = true;
      }
      if (rangeEnd && isSameDay(date, rangeEnd)) {
        isRangeEnd = true;
        isSelected = true;
      }
      if (rangeStart && rangeEnd && !isRangeStart && !isRangeEnd) {
        const t = date.getTime();
        isInRange = t > rangeStart.getTime() && t < rangeEnd.getTime();
      }
    }

    days.push({ date, isCurrentMonth, isToday, isSelected, isDisabled: isDisabledDate, isRangeStart, isRangeEnd, isInRange });
    cur.setDate(cur.getDate() + 1);
  }

  return days;
}

export function getSelectedDatesArray(value: CalendarValue, mode: CalendarMode): Date[] {
  if (!value) return [];
  if (mode === 'single') return [value as Date];
  if ((mode === 'multiple' || mode === 'range') && Array.isArray(value)) return value;
  return [];
}

export function getDayId(index: number): string {
  return `n-calendar-day-${index}`;
}

export function getDayAriaLabel(day: CalendarDay): string {
  const dateStr = day.date.toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  return [
    dateStr,
    day.isToday && 'Today',
    day.isSelected && 'Selected',
    day.isRangeStart && 'Range start',
    day.isRangeEnd && 'Range end',
    day.isInRange && 'In range',
    !day.isCurrentMonth && 'Outside month',
    day.isDisabled && 'Disabled',
  ]
    .filter(Boolean)
    .join(', ');
}

export function getWeekdayLabels(locale: string, weekStartsOn: 0 | 1): string[] {
  const labels: string[] = [];
  for (let i = 0; i < 7; i++) {
    const dayIndex = (weekStartsOn + i) % 7;
    // Jan 7, 2024 is a Sunday
    const date = new Date(2024, 0, 7 + dayIndex);
    labels.push(new Intl.DateTimeFormat(locale, { weekday: 'short' }).format(date));
  }
  return labels;
}

export function getMonthNames(locale: string): string[] {
  return Array.from({ length: 12 }, (_, i) =>
    new Intl.DateTimeFormat(locale, { month: 'long' }).format(new Date(2024, i, 1)),
  );
}

export function normalizeCalendarValue(v: CalendarValue): CalendarValue {
  if (!v) return v;
  if (v instanceof Date) return toValidDate(v);
  if (Array.isArray(v)) {
    return v.reduce<Date[]>((acc, d) => {
      const date = toValidDate(d);
      if (date) acc.push(date);
      return acc;
    }, []);
  }
  return toValidDate(v);
}

export function toValidDate(value: unknown): Date | null {
  if (value instanceof Date) return isNaN(value.getTime()) ? null : value;

  if (typeof value === 'number' && value.toString().length === 8) {
    const s = value.toString();
    return makeSafeDate(+s.slice(0, 4), +s.slice(4, 6) - 1, +s.slice(6, 8));
  }

  if (typeof value === 'string' && /^\d{8}$/.test(value)) {
    return makeSafeDate(+value.slice(0, 4), +value.slice(4, 6) - 1, +value.slice(6, 8));
  }

  const date = new Date(value as string | number | Date);
  if (isNaN(date.getTime())) return null;
  return makeSafeDate(date.getFullYear(), date.getMonth(), date.getDate());
}

