import { Component, signal } from '@angular/core';
import { CalendarComponent } from '../calendar.component';
import type { CalendarValue } from '../calendar.types';

@Component({
  selector: 'demo-calendar-default',
  standalone: true,
  imports: [CalendarComponent],
  template: `
    <div class="flex flex-col items-center gap-4">
      <n-calendar [(nValue)]="value" />
      <p class="text-sm text-muted-foreground">
        Selecionado:
        <span class="text-foreground font-medium">
          {{ value() ? asDate(value())!.toLocaleDateString() : 'nenhum' }}
        </span>
      </p>
    </div>
  `,
})
export class CalendarDefaultDemo {
  value = signal<CalendarValue>(null);

  asDate(v: CalendarValue): Date | null {
    return v instanceof Date ? v : null;
  }
}

import { Component } from '@angular/core';
import { CalendarComponent } from '../calendar.component';

@Component({
  selector: 'demo-calendar-disabled',
  standalone: true,
  imports: [CalendarComponent],
  template: `<n-calendar [nDisabled]="true" />`,
})
export class CalendarDisabledDemo {}

import { Component, signal } from '@angular/core';
import { CalendarComponent } from '../calendar.component';
import type { CalendarValue } from '../calendar.types';

@Component({
  selector: 'demo-calendar-multiple',
  standalone: true,
  imports: [CalendarComponent],
  template: `
    <div class="flex flex-col items-center gap-4">
      <n-calendar nMode="multiple" [(nValue)]="value" />
      <p class="text-sm text-muted-foreground">
        {{ count() }} data(s) selecionada(s)
      </p>
    </div>
  `,
})
export class CalendarMultipleDemo {
  value = signal<CalendarValue>(null);

  count() {
    const v = this.value();
    return Array.isArray(v) ? v.length : 0;
  }
}

import { Component, computed, signal } from '@angular/core';
import { CalendarComponent } from '../calendar.component';
import type { CalendarValue } from '../calendar.types';

@Component({
  selector: 'demo-calendar-range',
  standalone: true,
  imports: [CalendarComponent],
  template: `
    <div class="flex flex-col items-center gap-4">
      <n-calendar nMode="range" [(nValue)]="value" />
      <p class="text-sm text-muted-foreground">
        {{ rangeLabel() }}
      </p>
    </div>
  `,
})
export class CalendarRangeDemo {
  value = signal<CalendarValue>(null);

  rangeLabel = computed(() => {
    const v = this.value();
    if (!Array.isArray(v) || v.length === 0) return 'Selecione o início do intervalo';
    if (v.length === 1) return `De ${v[0].toLocaleDateString()} — selecione o fim`;
    return `${v[0].toLocaleDateString()} → ${v[1].toLocaleDateString()}`;
  });
}

import { Component } from '@angular/core';
import { FormControl, ReactiveFormsModule, Validators } from '@angular/forms';
import { CalendarComponent } from '../calendar.component';

@Component({
  selector: 'demo-calendar-with-form',
  standalone: true,
  imports: [CalendarComponent, ReactiveFormsModule],
  template: `
    <div class="flex flex-col items-center gap-4">
      <n-calendar [formControl]="dateControl" />
      <div class="text-sm space-y-1 text-center">
        <p class="text-muted-foreground">
          Valor: <span class="text-foreground font-medium">{{ displayValue() }}</span>
        </p>
        <p [class]="dateControl.valid ? 'text-green-600' : 'text-destructive'">
          {{ dateControl.valid ? 'Válido' : 'Obrigatório' }}
        </p>
      </div>
      <button
        type="button"
        class="text-xs text-muted-foreground underline hover:text-foreground"
        (click)="dateControl.reset()"
      >
        Limpar
      </button>
    </div>
  `,
})
export class CalendarWithFormDemo {
  dateControl = new FormControl<Date | null>(null, Validators.required);

  displayValue() {
    const v = this.dateControl.value;
    return v instanceof Date ? v.toLocaleDateString() : 'nenhum';
  }
}
